PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?instrumentname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:instrumentId ?cg . ?child a :Instruments ; p:id ?cg . ?l p:technicianId ?pg . ?parent a :Lab_Technicians ; p:id ?pg . } GROUP BY ?child }
  ?child p:instrumentName ?instrumentname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Lab_Technicians } }
  FILTER(?nf = ?total)
}

