PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:instrumentId ?cg . ?child a :Instruments ; p:id ?cg . ?l p:technicianId ?pg . ?parent a :Lab_Technicians ; p:id ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Lab_Technicians } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?description WHERE {
  ?lab_technicians_instruments a :Lab_Technicians_Instruments .
